  if(/(отмени|отменить)\s+все(?:\s+предыдущие)?(?:\s+действия)?/.test(low)){const stack=state.assistantUndoStack||[];if(!stack.length)return 'Нет сохранённых действий AI-помощника, которые можно отменить.';const count=stack.length,snapshot=stack[0];state.assistantUndoStack=[];restoreAssistantSnapshot(snapshot);return `Готово: отменено действий AI-помощника: ${count}. Данные возвращены к состоянию до первого из них.`}
  if(low.includes('отмени последнее')||low.includes('отменить последнее')){const stack=state.assistantUndoStack||[];if(stack.length){const snapshot=stack.pop();restoreAssistantSnapshot(snapshot);return 'Готово: последнее действие AI-помощника отменено.'}const action=state.lastAssistantAction;if(!action?.lessonIds?.length)return 'Нет сохранённого действия, которое можно отменить.';const ids=new Set(action.lessonIds);state.lessons.filter(l=>ids.has(l.id)).forEach(l=>{l.status='cancelled';reconcileLessonCharges(l)});state.lessons=state.lessons.filter(l=>!ids.has(l.id));state.lastAssistantAction=null;return `Готово: удалено ${ids.size} занятий из последнего массового действия.`}
