  const renameStudent=text.match(/переименуй\s+учени(?:ка|цу)\s+(.+?)\s+на\s+(.+)/i);if(renameStudent){const target=findStudentInText(renameStudent[1]),parts=titleCase(renameStudent[2]).split(/\s+/);if(!target||parts.length<2)return 'Не удалось определить ученика или новое имя и фамилию.';const old=`${target.first} ${target.last}`;target.first=parts[0];target.last=parts.slice(1).join(' ');return `Ученик ${old} переименован в ${target.first} ${target.last}.`}
  if(/удал(?:и|ить).*(ученика|ученицу)/.test(low)&&!/(из группы|из пары)/.test(low)&&student)return queueAssistantAction('delete_student',{id:student.id},`Удалить ученика ${student.first} ${student.last} из базы?`);
  if(/(измени|редактируй|отредактируй|поменяй).*(учени|данн)|перенеси учени/.test(low)&&student){const changed=[];if(teacher&&teacher!==student.teacher){student.teacher=teacher;changed.push(`преподаватель: ${teacher}`)}const slots=parseScheduleSlots(text);if(slots.length){student.scheduleSlots=slots;student.days=slots.map(x=>x.day);student.time=slots[0].time;changed.push(`расписание: ${studentScheduleText(student)}`)}if(low.includes('индивиду')){student.format='individual';changed.push('индивидуальный формат')}else if(low.includes('пар')){student.format='pair';changed.push('формат: пара')}else if(low.includes('групп')){student.format='group';changed.push('формат: группа')}const contact=text.match(/контакт\s*[:—-]?\s*([^,]+)/i)?.[1];if(contact){student.contact=contact.trim();changed.push('контакт обновлён')}return changed.length?`Карточка ${student.first} ${student.last} обновлена: ${changed.join('; ')}.`:'Я нашёл ученика, но не понял, какое поле изменить. Укажите преподавателя, расписание по дням, формат или контакт.'}

