  const addTeacher=low.match(/добав(?:ь|ить)\s+(?:преподавател[ья]|учителя)\s+(.+)/);if(addTeacher){const name=titleCase(addTeacher[1]);if(state.teachers.some(t=>t.toLowerCase()===name.toLowerCase()))return `Преподаватель ${name} уже есть в списке.`;state.teachers.push(name);return `Готово: преподаватель ${name} добавлен.`}
  if(/удал(?:и|ить).*(преподавател|учител)/.test(low)&&teacher)return queueAssistantAction('delete_teacher',{name:teacher},`Удалить преподавателя ${teacher}? Активные назначения будут очищены.`);

