  if(/добав(?:ь|ить).*(в группу|в пару)/.test(low)&&student&&group){if(!group.studentIds.includes(student.id))group.studentIds.push(student.id);student.format=group.type;return `${student.first} ${student.last} добавлен(а) в «${group.name}».`}
  if(/(убери|исключи|удали).*(из группы|из пары)/.test(low)&&student&&group){group.studentIds=group.studentIds.filter(id=>id!==student.id);return `${student.first} ${student.last} удалён(а) из «${group.name}».`}
  const renameGroup=text.match(/переименуй\s+(?:группу|пару)\s+(.+?)\s+на\s+(.+)/i);if(renameGroup){const target=findGroupInText(renameGroup[1]);if(!target)return 'Группа для переименования не найдена.';const old=target.name;target.name=renameGroup[2].trim();return `Группа «${old}» переименована в «${target.name}».`}
